def bump_share_rule(model, j, h):
    return model.bh[j, h] <= 0.25 * sum(model.bh[jj, h] for jj in model.j)
model.bump_share = Constraint(model.j, model.h, rule=bump_share_rule)

def half_cap_rule(model, i, j):
    if (i, j) not in model.ij:
        return Constraint.Skip
    return model.x[i, j] <= 0.5 * model.aa[i]
model.half_cap = Constraint(model.i, model.j, rule=half_cap_rule)

def z_floor_rule(model, j):
    return model.z[j] >= sum(model.dd[j, h] for h in model.h) / 5.0
model.z_floor = Constraint(model.j, rule=z_floor_rule)

def peak_bump_rule(model, h):
    return sum(model.bh[j, h] for j in model.j) <= 200
model.peak_bump = Constraint(model.h, rule=peak_bump_rule)
